SELECT user_id, COUNT(DISTINCT simulation_id) AS num_simulations 
FROM user_simulations 
GROUP BY user_id;

SELECT AVG(average_payoff) AS average_payoff_for_strategy_2
FROM round_results
WHERE strategy_id = 2;

SELECT round_id, total_agents, 
  DENSE_RANK() OVER (ORDER BY total_agents DESC) as rank
FROM rounds;

SELECT COUNT(DISTINCT simulation_id)
FROM rounds
WHERE round_number > 10;

SELECT COUNT(round_id) AS number_of_rounds
FROM round_results
WHERE strategy_id = 2;
